// parseColOpts splits "label::value|label::value" into [][label, value] pairs.
// If an entry has no "::" separator, label and value are identical.
func parseColOpts(raw string) [][2]string {
	if raw == "" {
		return nil
	}
	parts := strings.Split(raw, "|")
	out := make([][2]string, 0, len(parts))
	for _, p := range parts {
		if i := strings.Index(p, "::"); i >= 0 {
			out = append(out, [2]string{p[:i], p[i+2:]})
		} else {
			out = append(out, [2]string{p, p})
		}
	}
	return out
}

// colOptsJSON serialises ColOptions as a compact JSON object for the
// data-col-opts attribute so kvBlockAddRow can build selects for new rows.
func colOptsJSON(m map[string]string) string {
	if len(m) == 0 {
		return ""
	}
	var b strings.Builder
	b.WriteByte('{')
	first := true
	for k, v := range m {
		if !first {
			b.WriteByte(',')
		}
		first = false
		b.WriteByte('"')
		b.WriteString(k)
		b.WriteString(`":"`)
		// escape double-quotes inside the value
		b.WriteString(strings.ReplaceAll(v, `"`, `\"`))
		b.WriteByte('"')
	}
	b.WriteByte('}')
	return b.String()
}

